import { Component, OnInit } from '@angular/core';
import { ChartConfiguration, ChartData, ChartType } from 'chart.js';
import { CommonService } from 'src/app/service/common.service';
import { NotificationService } from 'src/app/pages/notification/notification.service';
import { UtilsService } from 'src/app/helper/service/utils.service';
import { environment } from 'src/environments/environment';
import { ApiNameConstants } from 'src/app/constant/ApiNameConstants';
import { ConstantsApp } from 'src/app/constant/ConstantsApp';

@Component({
  selector: 'app-job-notification-chart',
  templateUrl: './job-notification-chart.component.html',
  styleUrls: ['./job-notification-chart.component.scss']
})
export class JobNotificationChartComponent implements OnInit {
  public barChartOptions: ChartConfiguration['options'] = {
    responsive: true,
    scales: {
      x: {},
      y: {
        beginAtZero: true
      }
    },
    plugins: {
      legend: {
        display: true,
      }
    }
  };
  public barChartLabels: string[] = ['Xem', 'Lưu', 'Ứng tuyển'];
  public barChartType: ChartType = 'bar';
  public barChartData: ChartData<'bar'> = {
    labels: this.barChartLabels,
    datasets: [{ 
      data: [0, 0, 0], 
      label: 'Số lượng',
      backgroundColor: ['#4CAF50', '#FFC107', '#2196F3'], // Xanh lá, Vàng, Xanh dương
      borderColor: ['#388E3C', '#FFA000', '#1976D2'],
      borderWidth: 1
    }]
  };

  public jobPosts: any[] = [];
  public selectedJob: any;

  constructor(
    private commonService: CommonService,
    private notificationService: NotificationService,
    private utilsService: UtilsService
  ) {}

  ngOnInit(): void {
    this.loadJobPosts();
  }

  loadJobPosts() {
    const recruiter = this.utilsService.getItem('user');
    if (!recruiter || recruiter.role !== 'RECRUITER') {
      console.warn('Không phải recruiter');
      return;
    }

    const functionName = 'loadJobPosts';
    const messageLog = 'Lấy danh sách bài đăng của recruiter';
    const apiUrl = environment.API_URI + ApiNameConstants.BS_JOB_GET_BY_RECRUITER;

    this.commonService
      .getDatas(apiUrl, functionName, messageLog)
      .subscribe(
        (res: any) => {
          if (res && res.data) {
            this.jobPosts = res.data.map((job: any) => ({
              id: job.id,
              name: job.name
            }));
            // Chọn bài đăng đầu tiên nếu có
            if (this.jobPosts.length > 0) {
              this.selectedJob = this.jobPosts[0];
              this.loadNotificationStats(this.selectedJob.id);
            }
          }
        },
        (error) => {
          console.error('Lỗi tải bài đăng:', error);
        }
      );
  }

  onJobSelected() {
    if (this.selectedJob) {
      this.loadNotificationStats(this.selectedJob.id);
    }
  }

  loadNotificationStats(postId: number) {
    const functionName = 'loadNotificationStats';
    const messageLog = 'Lấy thống kê thông báo theo postId';
    const apiUrl = `${environment.API_URI}bs-user/notifications/stats/${postId}`;

    this.commonService
      .getDatas(apiUrl, functionName, messageLog)
      .subscribe(
        (res: any) => {
          if (res) {
            const stats = res;
            this.barChartData = {
              labels: this.barChartLabels,
              datasets: [{
                data: [
                  stats['JOB_VIEW'] || 0,
                  stats['JOB_SAVE'] || 0,
                  stats['JOB_APPLY'] || 0
                ],
                label: `Thống kê cho bài đăng: ${this.selectedJob.name}`,
                backgroundColor: ['#4CAF50', '#FFC107', '#2196F3'],
                borderColor: ['#388E3C', '#FFA000', '#1976D2'],
                borderWidth: 1
              }]
            };
          }
        },
        (error) => {
          console.error('Lỗi tải thống kê:', error);
          this.barChartData = {
            labels: this.barChartLabels,
            datasets: [{ data: [0, 0, 0], label: `Thống kê cho bài đăng: ${this.selectedJob.name}` }]
          };
        }
      );
  }
}
